-- TradePilot local historical market data seed
-- Generated from local price_history only; no user trades, cash flows, email credentials, or account data are included.
-- Safe to run more than once: rows are upserted by (symbol, date, source).
BEGIN;
CREATE TEMP TABLE _price_history_seed (
  id text NOT NULL,
  symbol text NOT NULL,
  provider_symbol text NOT NULL,
  price_date date NOT NULL,
  close numeric(30, 12) NOT NULL,
  adjusted_close numeric(30, 12),
  currency text NOT NULL,
  source text NOT NULL,
  created_at timestamptz NOT NULL,
  updated_at timestamptz NOT NULL
) ON COMMIT DROP;
SELECT id, symbol, provider_symbol, price_date, close, adjusted_close, currency, source, created_at, updated_at
FROM _price_history_seed
ON CONFLICT (symbol, date, source) DO UPDATE SET
  "providerSymbol" = EXCLUDED."providerSymbol",
  close = EXCLUDED.close,
  "adjustedClose" = EXCLUDED."adjustedClose",
  currency = EXCLUDED.currency,
  "updatedAt" = EXCLUDED."updatedAt";
COMMIT;
